import re

def redact_pii(text):
    patterns = {
        r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b': '[EMAIL]',
        r'\b\d{3}[-.]?\d{3}[-.]?\d{4}\b': '[PHONE]',
        r'\b\d{3}-?\d{2}-?\d{4}\b': '[SSN]',
        r'\b\d{5}\b': '[ZIP]'
    }
    for pattern, replacement in patterns.items():
        text = re.sub(pattern, replacement, text)
    return text

class PIIProtectedAgent:
    def __init__(self, agent):
        self.agent = agent

    def run(self, input_text):
        safe_input = redact_pii(input_text)
        result = self.agent.run(safe_input)
        return redact_pii(str(result))

# Usage
from smolagents import Agent
agent = PIIProtectedAgent(Agent(...))
result = agent.run('Contact john@example.com at 555-123-4567')

